from flask import Flask, request, Response
from prometheus_client import Counter, generate_latest, CONTENT_TYPE_LATEST
import re

app = Flask(__name__)

REQUEST_COUNTER = Counter(
    "http_requests_total",
    "Total HTTP requests",
    ["user_id", "session_id", "path"],
)

def normalize_label(value, default="unknown"):
    if value is None:
        return default
    value = str(value).strip()
    return value if value else default

@app.before_request
def track_request():
    user_id = normalize_label(request.headers.get("X-User-Id"))
    session_id = normalize_label(request.headers.get("X-Session-Id"))
    path = normalize_label(request.path, default="/")
    REQUEST_COUNTER.labels(user_id=user_id, session_id=session_id, path=path).inc()

@app.route("/")
def index():
    return "OK"

@app.route("/metrics")
def metrics():
    return Response(generate_latest(), mimetype=CONTENT_TYPE_LATEST)

@app.route("/<path:subpath>", methods=["GET", "POST", "PUT", "DELETE", "PATCH", "OPTIONS"])
def catch_all(subpath):
    return f"Requested: /{subpath}"

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=8000)